{
  "$schema": "https://opencode.ai/config.json",

  "plugin": [
    "oh-my-opencode@3.12.3",
    "opencode-openai-codex-auth@4.4.0",
    "opencode-gemini-auth@latest",
    // "opencode-antigravity-auth@1.6.0",

    "@plannotator/opencode@latest",

    // "@plannotator/opencode@0.15.5",
    "@franlol/opencode-md-table-formatter@0.0.3",
    "@nick-vi/opencode-type-inject@1.3.1",
    "@bastiangx/opencode-unmoji@0.3.11",
    "@tarquinen/opencode-dcp@latest"
    // "octto",
  ],

  "model": "openai/gpt-5.2",
  "autoupdate": true,
  "share": "disabled",

  "mcp": {
    "mcpproxy": {
      "url": "http://localhost:8080/mcp/",
      "type": "remote",
      "enabled": true
    }
  },

  "enabled_providers": [
    "openai",
    "zai-coding-plan",
    "opencode-go",
    "omniroute",
    "google",
    "github-copilot"
  ],

  "lsp": {
    "markdown": {
      "command": ["npx", "-y", "remark-language-server", "--stdio"],
      "extensions": [".md"]
    }
  },

  "provider": {
    "openai": {
      "name": "OpenAI",
      "options": {
        "reasoningEffort": "medium",
        "reasoningSummary": "auto",
        "textVerbosity": "medium",
        "include": ["reasoning.encrypted_content"],
        "store": false
      },
      "models": {
        "gpt-5.2": {
          "name": "GPT 5.2 (OAuth)",
          "limit": { "context": 272000, "output": 128000 },
          "modalities": { "input": ["text", "image"], "output": ["text"] },
          "variants": {
            "none": {
              "reasoningEffort": "none",
              "reasoningSummary": "auto",
              "textVerbosity": "medium"
            },
            "low": {
              "reasoningEffort": "low",
              "reasoningSummary": "auto",
              "textVerbosity": "medium"
            },
            "medium": {
              "reasoningEffort": "medium",
              "reasoningSummary": "auto",
              "textVerbosity": "medium"
            },
            "high": {
              "reasoningEffort": "high",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            },
            "xhigh": {
              "reasoningEffort": "xhigh",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            }
          }
        },
        "gpt-5.2-codex": {
          "name": "GPT 5.2 Codex (OAuth)",
          "limit": { "context": 272000, "output": 128000 },
          "modalities": { "input": ["text", "image"], "output": ["text"] },
          "variants": {
            "low": {
              "reasoningEffort": "low",
              "reasoningSummary": "auto",
              "textVerbosity": "medium"
            },
            "medium": {
              "reasoningEffort": "medium",
              "reasoningSummary": "auto",
              "textVerbosity": "medium"
            },
            "high": {
              "reasoningEffort": "high",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            },
            "xhigh": {
              "reasoningEffort": "xhigh",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            }
          }
        },
        "gpt-5.1-codex-max": {
          "name": "GPT 5.1 Codex Max (OAuth)",
          "limit": { "context": 272000, "output": 128000 },
          "modalities": { "input": ["text", "image"], "output": ["text"] },
          "variants": {
            "low": {
              "reasoningEffort": "low",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            },
            "medium": {
              "reasoningEffort": "medium",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            },
            "high": {
              "reasoningEffort": "high",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            },
            "xhigh": {
              "reasoningEffort": "xhigh",
              "reasoningSummary": "detailed",
              "textVerbosity": "medium"
            }
          }
        },
        "gpt-5.1-codex-mini": {
          "name": "GPT 5.1 Codex Mini (OAuth)",
          "limit": { "context": 128000, "output": 64000 },
          "modalities": { "input": ["text"], "output": ["text"] }
        }
      }
    },
    "zai-coding-plan": {
      "name": "Zhipu AI",
      "models": {
        "glm-4.7": {
          "name": "GLM 4.7",
          "limit": { "context": 128000, "output": 4096 }
        },
        "glm-4.7-flash": {
          "name": "GLM 4.7 Flash",
          "limit": { "context": 128000, "output": 4096 }
        },
        "glm-4.6v": {
          "name": "GLM 4.6 Vision",
          "limit": { "context": 8000, "output": 4096 },
          "modalities": { "input": ["text", "image"], "output": ["text"] }
        }
      }
    },
    "omniroute": {
      "npm": "@ai-sdk/openai-compatible",
      "name": "OMNi",
      "options": {
        "baseURL": "https://omniroute.e6ejok.easypanel.host/v1",
        "apiKey": "{env:OMNIROUTE_TOKEN}"
      },
      "models": {
        "reasoning-main": { "name": "Reasoning Main", "tools": true },
        "reasoning-cheap": { "name": "Reasoning Cheap", "tools": true },
        "coding-main": { "name": "Coding Main", "tools": true },
        "coding-cheap": { "name": "Coding Cheap", "tools": true },
        "deep-premium": { "name": "Deep Premium", "tools": true },
        "research-fast": { "name": "Research Fast", "tools": true },
        "quick-free": { "name": "Quick Free", "tools": true },
        "vision-main": { "name": "Vision Main", "tools": true },
        "writing-cheap": { "name": "Writing Cheap", "tools": true }
      }
    },
    "google": {
      "name": "Google",
      "options": {
        "only_defined_models": true,
        "discover": false,
        "models_include": [
          "gemini-3.1-pro-preview",
          "gemini-3-pro-preview",
          "gemini-3-flash-preview",
          "gemini-2.5-pro",
          "gemini-2.5-flash",
          "gemini-2.5-flash-lite"
        ]
      },
      "models": {
        "gemini-3.1-pro-preview": {
          "name": "Gemini 3.1 Pro Preview",
          "limit": { "context": 2000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        },
        "gemini-3-pro-preview": {
          "name": "Gemini 3 Pro Preview",
          "limit": { "context": 2000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        },
        "gemini-3-flash-preview": {
          "name": "Gemini 3 Flash Preview",
          "limit": { "context": 1000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        },
        "gemini-2.5-pro": {
          "name": "Gemini 2.5 Pro",
          "limit": { "context": 2000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        },
        "gemini-2.5-flash": {
          "name": "Gemini 2.5 Flash",
          "limit": { "context": 1000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        },
        "gemini-2.5-flash-lite": {
          "name": "Gemini 2.5 Flash Lite",
          "limit": { "context": 1000000, "output": 65536 },
          "modalities": { "input": ["text", "image", "pdf"], "output": ["text"] }
        }
      }
    }
  }
}

