{
  "$schema": "https://raw.githubusercontent.com/code-yeongyu/oh-my-openagent/dev/assets/oh-my-opencode.schema.json",
  "hashline_edit": true,
  "agents": {
    "sisyphus": {
      "model": "google/gemini-3.1-pro-preview",
      "fallback_models": ["google/gemini-2.5-pro"]
    },
    "atlas": {
      "model": "google/gemini-3.1-pro-preview",
      "fallback_models": ["google/gemini-2.5-pro"]
    },
