      "model": "google/gemini-3-flash-preview",
      "fallback_models": ["google/gemini-2.5-flash"]
    },
    "explore": {
      "model": "google/gemini-3-flash-preview",
      "fallback_models": ["google/gemini-2.5-flash"]
    },
